from dataclasses import dataclass
from enum import Enum
from typing import Optional

class ViolationSeverity(Enum):
    LOW = "low"          # Minor inadvertent breach, no harm
    MEDIUM = "medium"    # Conditional use without approval, limited exposure
    HIGH = "high"        # Prohibited use, material risk or actual harm
    CRITICAL = "critical"  # Intentional, repeated, or causing significant damage

@dataclass
class AUPViolation:
    employee_id: str
    incident_date: str
    description: str
    severity: ViolationSeverity
    data_classification: str   # e.g. "confidential", "pii", "internal"
    tool_used: str
    approved_tool: bool
    data_exfiltrated: bool

    def requires_immediate_suspension(self) -> bool:
        return (
            self.severity == ViolationSeverity.CRITICAL or
            (self.severity == ViolationSeverity.HIGH and self.data_exfiltrated)
        )

    def requires_legal_notification(self) -> bool:
        return (
            self.data_classification in ("pii", "special_category", "confidential") and
            self.data_exfiltrated
        )

    def standard_response(self) -> str:
        responses = {
            ViolationSeverity.LOW:      "Remind + re-training; document in log",
            ViolationSeverity.MEDIUM:   "Formal warning; manager notification; mandatory re-training",
            ViolationSeverity.HIGH:     "HR investigation; possible disciplinary; legal review",
            ViolationSeverity.CRITICAL: "Immediate suspension pending investigation; legal and DPO notification",
        }
        return responses[self.severity]

# Shadow AI detection helper — check approved tool registry
from dataclasses import dataclass, field
from typing import Optional

APPROVED_DOMAINS = {
    "api.openai.com",            # enterprise licence
    "copilot.microsoft.com",     # enterprise M365 integration
    "generativelanguage.googleapis.com",  # approved Vertex endpoint
}

@dataclass
class ProxyLogEntry:
    employee_id: str
    timestamp: str
    destination_domain: str
    bytes_uploaded: int

    def is_shadow_ai_candidate(self) -> bool:
        known_ai_domains = [
            "chat.openai.com", "claude.ai", "bard.google.com",
            "huggingface.co", "perplexity.ai",
        ]
        return (
            any(d in self.destination_domain for d in known_ai_domains) and
            self.destination_domain not in APPROVED_DOMAINS and
            self.bytes_uploaded > 1024  # data was sent, not just a page load
        )

@dataclass
class ShadowAIReport:
    period_start: str
    period_end: str
    flagged_entries: list[ProxyLogEntry] = field(default_factory=list)

    def high_volume_employees(self, threshold_bytes: int = 100_000) -> list[str]:
        totals: dict[str, int] = {}
        for entry in self.flagged_entries:
            totals[entry.employee_id] = totals.get(entry.employee_id, 0) + entry.bytes_uploaded
        return [eid for eid, total in totals.items() if total >= threshold_bytes]

    def summary(self) -> str:
        return (
            f"Period: {self.period_start} – {self.period_end} | "
            f"Flagged events: {len(self.flagged_entries)} | "
            f"High-volume employees: {len(self.high_volume_employees())}"
        )

from dataclasses import dataclass
from typing import Optional
import re

class AUPDecision(str):
    PERMIT = "permit"
    CONDITIONAL = "conditional"
    BLOCK = "block"

PROHIBITED_PATTERNS = [
    r"\b(password|secret|api[_-]?key|token)\s*[:=]\s*\S+",  # credential leakage
    r"\b(SSN|social security|NI number)\s*[:=]?\s*\d",        # government ID numbers
    r"generate.*malware|write.*exploit|bypass.*auth",              # harmful code intent
]

CONDITIONAL_KEYWORDS = [
    "customer name", "employee", "date of birth",
    "performance review", "salary", "contract value",
]

@dataclass
class PromptGovernanceResult:
    decision: str
    matched_rule: Optional[str]
    redacted_prompt: Optional[str]
    audit_required: bool

def evaluate_prompt(prompt: str, user_clearance: str) -> PromptGovernanceResult:
    for pattern in PROHIBITED_PATTERNS:
        if re.search(pattern, prompt, re.IGNORECASE):
            return PromptGovernanceResult(
                decision=AUPDecision.BLOCK,
                matched_rule=pattern,
                redacted_prompt=None,
                audit_required=True,
            )

    for kw in CONDITIONAL_KEYWORDS:
        if kw in prompt.lower():
            if user_clearance not in ("hr_approved", "data_owner"):
                return PromptGovernanceResult(
                    decision=AUPDecision.CONDITIONAL,
                    matched_rule=f"conditional keyword: {kw}",
                    redacted_prompt=prompt,
                    audit_required=True,
                )

    return PromptGovernanceResult(
        decision=AUPDecision.PERMIT,
        matched_rule=None,
        redacted_prompt=prompt,
        audit_required=False,
    )
